VALUES
  ('police-8b7f1efc-moex-00687', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '公共政策理論中認為，無論是垂直或水平分工，同樣都存在著整合的問題；H. Mintzberg 因此提 出了六項整合的模式，下列何者並非Mintzberg所提出的模式之一？', '["輸出標準化", "直接督導", "相互妥協", "技巧標準化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "afd95778df81", "answer_pdf_sha1": "6dffaa622bf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00688', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', 'D.Kennedy（1983）認為服務人群的機關組織應具備一些特質，下列何者不是其所具備的特質：', '["服務對象遭遇到的問題都是特定的問題", "服務廣泛", "能提供系統整合的服務", "機關能提供一般性的服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "afd95778df81", "answer_pdf_sha1": "6dffaa622bf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00689', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '主張民眾會因為得知某人遭受犯罪侵害，或是從媒體觀看犯罪被害新聞，而產生被害恐懼感，此 在學理上稱為：', '["責備被害人（blamingthevictim）", "重複被害（repeatvictimization）", "被害衝擊（victimimpact）", "替代被害（vicariousvictimization）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "afd95778df81", "answer_pdf_sha1": "6dffaa622bf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00690', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '在第69期警政雙月刊中刊載徵文活動「預防犯罪新思惟-以多元宣導推播預防犯罪IPC理念」，所 謂的IPC指的是預防犯罪從我做起（I prevent crime）。在政策溝通的理論中，此種只考慮警察的 手段（徵文），而不考慮目的本身是否為民眾所接受，此種理性被稱為：', '["工具理性", "實質理性", "目的理性", "溝通理性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "afd95778df81", "answer_pdf_sha1": "6dffaa622bf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00691', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '根據國內外相關的實證研究發現，被害人參與修復式司法方案後，可以提升那幾項的正義感受？', '["程序正義", "應報式正義", "實質正義", "互動式正義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "afd95778df81", "answer_pdf_sha1": "6dffaa622bf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00692', 'police-8b7f1efc', 'police-8b7f1efc-moex-110-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '由於工業化與都市化等社會變遷的影響，被稱為現代警政之父的時任英國內政部長皮爾爵士（Sir Robert Peel）認為，犯罪問題引發了普遍的社會不安，積極推動設立新警察的計畫，於何年成立 「倫敦首都警察廳」？', '["1829", "1835", "1841", "1851"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "afd95778df81", "answer_pdf_sha1": "6dffaa622bf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
